// Extract article body from HTML
const html = $input.first().json.body || $input.first().json.html;

// Simple extraction of main content
const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
const articleBody = articleMatch ? articleMatch[1] : html;

// Extract sections based on H2 headers
const sections = [];
const h2Regex = /<h2[^>]*id="([^"]+)"[^>]*>([^<]+)<\/h2>([\s\S]*?)(?=<h2|<\/article)/gi;
let match;
while ((match = h2Regex.exec(articleBody)) !== null) {
  sections.push({
    id: match[1],
    title: match[2],
    content: match[3].trim()
  });
}

return [{json: {sections, articleBody}}];
